SELECT m.id, m.parent_id, m.menu_name, m.menu_type, m.path, m.component, m.query, m.is_frame, m.is_cache, m.status, m.visible, m.perms, m.icon, m.sort, m.title, m.alias, m.description, m.external, m.new_window, m.affix, m.hide_breadcrumb, m.hide_tab, m.hide_menu, m.hide_children, m.hide_search, m.hide_footer, m.hide_setting, m.hide_i18n, m.hide_fullscreen, m.hide_refresh, m.hide_help, m.hide_notice, m.hide_user_info, m.hide_logout, m.ext_data, m.create_time, m.update_time, m.create_by, m.update_by, m.remark, p.menu_name as parent_name FROM sys_menu m LEFT JOIN sys_menu p ON m.parent_id = p.id
m.deleted = 0
AND m.menu_name LIKE CONCAT('%', #{query.menuName}, '%')
AND m.menu_type = #{query.menuType}
AND m.status = #{query.status}
AND m.visible = #{query.visible}
AND m.perms LIKE CONCAT('%', #{query.perms}, '%')
AND m.parent_id = #{query.parentId}
AND m.path LIKE CONCAT('%', #{query.path}, '%')
AND m.component LIKE CONCAT('%', #{query.component}, '%')
AND m.create_time >= #{query.startTime}
AND m.create_time <= #{query.endTime}
ORDER BY m.sort ASC, m.create_time DESC

